27	
28	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
29	
30	const INSURANCE_VALUE: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const insuranceValueFor = (type: string): number => INSURANCE_VALUE[type] ?? 0;
40	
41	const DEDUCTIBLE = 100;
42	const CAP_MULTIPLIER = 2;
43	
44	const FIRST_INSURANCE_RATE = 0.1;
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	const BLOCK_SIZE = 3;
48	const BLOCK_BASE_PREMIUM = 60;
49	
50	const countByType = (items: Item[]): Map<string, number> => {
51	  const counts = new Map<string, number>();
52	  for (const item of items) {
53	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
54	  }
55	  return counts;
56	};
57	
58	const groupBase = (type: string, count: number): number =>
59	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
60	    ? BLOCK_BASE_PREMIUM
61	    : count * basePremiumFor(type);
62	
63	const policyBase = (items: Item[]): number =>
64	  Array.from(countByType(items)).reduce(
65	    (total, [type, count]) => total + groupBase(type, count),
66	    0,
67	  );
