69	const LOYALTY_RATE = 0.2;
70	const LOYALTY_THRESHOLD_YEARS = 2;
71	const FOLLOW_UP_RATE = 0.15;
72	
73	type PolicyContext = { customer: Customer; isFollowUp: boolean };
74	
75	type PolicyModifier = {
76	  applies: (ctx: PolicyContext) => boolean;
77	  rate: number;
78	  sign: 1 | -1;
79	};
80	
81	const POLICY_MODIFIERS: PolicyModifier[] = [
82	  { applies: () => true, rate: FIRST_INSURANCE_RATE, sign: +1 },
83	  {
84	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
85	    rate: LOYALTY_RATE,
86	    sign: -1,
87	  },
88	  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE, sign: -1 },
89	];
90	
91	const policyAdjustments = (base: number, ctx: PolicyContext): number =>
92	  POLICY_MODIFIERS.reduce(
93	    (total, mod) => total + (mod.applies(ctx) ? mod.sign * base * mod.rate : 0),
94	    0,
95	  );
96	
97	const CURSE_RATE = 0.5;
98	const HIGH_ENCHANTMENT_RATE = 0.3;
99	const HIGH_ENCHANTMENT_THRESHOLD = 5;
100	
101	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
102	  applies ? basePremiumFor(item.type) * rate : 0;
103	
104	const curseSurcharge = (item: Item): number =>
105	  surchargeWhen(item, item.cursed === true, CURSE_RATE);
106	
107	const highEnchantmentSurcharge = (item: Item): number =>
108	  surchargeWhen(
109	    item,
110	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
111	    HIGH_ENCHANTMENT_RATE,
112	  );
113	
114	const itemSurcharges = (items: Item[]): number =>
115	  items.reduce(
116	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
117	    0,
118	  );
119	
120	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
121	  const base = policyBase(items);
122	  return Math.ceil(
123	    base + itemSurcharges(items) + policyAdjustments(base, ctx) + PROCESSING_FEE,
124	  );
125	};
126	
127	const insuranceSum = (items: Item[]): number =>
128	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
129	
130	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
131	
132	const claimPayout = (claim: ClaimStep): number =>
133	  claim.incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
134	
135	type QuoteResult = { premium: number };
136	type ClaimResult = { payout: number; remainingCap: number };
137	type StepResult = QuoteResult | ClaimResult;
