139	export const processScenario = (scenario: Scenario): unknown => {
140	  let priorQuotes = 0;
141	  const policyCaps = new Map<number, number>();
142	  const results: StepResult[] = scenario.steps.map((step, index) => {
143	    if (step.op === "quote") {
144	      const isFollowUp = priorQuotes > 0;
145	      priorQuotes += 1;
146	      policyCaps.set(index, CAP_MULTIPLIER * insuranceSum(step.items));
147	      return {
148	        premium: quotePremium(step.items, {
149	          customer: scenario.customer,
150	          isFollowUp,
151	        }),
152	      };
153	    }
154	    const cap = policyCaps.get(step.policy) ?? 0;
155	    const payout = claimPayout(step);
156	    const remainingCap = cap - payout;
157	    policyCaps.set(step.policy, remainingCap);
158	    return { payout, remainingCap };
159	  });
160	  return { results };
161	};
